import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"A-MEM: Agentic Memory for LLM Agents","description":"","frontmatter":{"title":"A-MEM: Agentic Memory for LLM Agents","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2502.12110-a-mem-arxiv.md","filePath":"research/agent-harness/references/2502.12110-a-mem-arxiv.md","lastUpdated":1779796674000}'),i={name:"research/agent-harness/references/2502.12110-a-mem-arxiv.md"};function l(s,e,o,h,d,m){return t(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="a-mem-agentic-memory-for-llm-agents" tabindex="-1">A-MEM: Agentic Memory for LLM Agents <a class="header-anchor" href="#a-mem-agentic-memory-for-llm-agents" aria-label="Permalink to &quot;A-MEM: Agentic Memory for LLM Agents&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2502.12110" target="_blank" rel="noreferrer">https://arxiv.org/abs/2502.12110</a></li><li><strong>發表</strong>: NeurIPS 2025</li><li><strong>GitHub</strong>: <a href="https://github.com/agiresearch/a-mem" target="_blank" rel="noreferrer">https://github.com/agiresearch/a-mem</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — MemGPT 的後繼；引入 Zettelkasten 動態連結機制，解決靜態向量檢索的局限</li></ul><hr><h2 id="核心創新-zettelkasten-知識網絡" tabindex="-1">核心創新：Zettelkasten 知識網絡 <a class="header-anchor" href="#核心創新-zettelkasten-知識網絡" aria-label="Permalink to &quot;核心創新：Zettelkasten 知識網絡&quot;">​</a></h2><p><strong>Zettelkasten</strong>（德語「索引卡盒」）是德國社會學家 Niklas Luhmann 的筆記方法：每則筆記有唯一 ID，透過雙向連結形成知識網絡，整體大於各部分之和。</p><p>A-Mem 將這個原理應用到 agent 記憶：每次存入的記憶不只是孤立的 embedding，而是與其他記憶形成動態連結。</p><hr><h2 id="技術架構" tabindex="-1">技術架構 <a class="header-anchor" href="#技術架構" aria-label="Permalink to &quot;技術架構&quot;">​</a></h2><h3 id="記憶生成-memory-creation" tabindex="-1">記憶生成（Memory Creation） <a class="header-anchor" href="#記憶生成-memory-creation" aria-label="Permalink to &quot;記憶生成（Memory Creation）&quot;">​</a></h3><p>新記憶加入時，系統自動生成結構化筆記，包含：</p><ul><li><strong>上下文描述</strong>（contextual description）</li><li><strong>關鍵詞</strong>（keywords）</li><li><strong>標籤</strong>（tags）</li><li><strong>元數據</strong>（metadata: 時間戳、來源、重要性）</li></ul><h3 id="動態連結-dynamic-linking" tabindex="-1">動態連結（Dynamic Linking） <a class="header-anchor" href="#動態連結-dynamic-linking" aria-label="Permalink to &quot;動態連結（Dynamic Linking）&quot;">​</a></h3><p>LLM 判斷新記憶與現有記憶之間是否應建立連結：</p><ul><li>主題相關性</li><li>因果關係</li><li>時間鄰近性</li><li>概念互補性</li></ul><h3 id="智能檢索-intelligent-retrieval" tabindex="-1">智能檢索（Intelligent Retrieval） <a class="header-anchor" href="#智能檢索-intelligent-retrieval" aria-label="Permalink to &quot;智能檢索（Intelligent Retrieval）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查詢 → 提取 query embedding</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>語義搜索找到相關記憶</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>同一「知識盒」中的連結記憶也自動載入</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>形成豐富的上下文網絡</span></span></code></pre></div><hr><h2 id="與-memgpt-的比較" tabindex="-1">與 MemGPT 的比較 <a class="header-anchor" href="#與-memgpt-的比較" aria-label="Permalink to &quot;與 MemGPT 的比較&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>MemGPT</th><th>A-Mem</th></tr></thead><tbody><tr><td>記憶存儲</td><td>三層（main / recall / archive）</td><td>互連知識網絡</td></tr><tr><td>檢索機制</td><td>向量搜索（獨立 embedding）</td><td>Zettelkasten 動態連結</td></tr><tr><td>記憶關係</td><td>孤立節點</td><td>雙向連結圖</td></tr><tr><td>更新策略</td><td>靜態存儲</td><td>動態演進（新記憶影響舊連結）</td></tr></tbody></table><hr><h2 id="實驗成果" tabindex="-1">實驗成果 <a class="header-anchor" href="#實驗成果" aria-label="Permalink to &quot;實驗成果&quot;">​</a></h2><ul><li>在 <strong>6 個基礎模型</strong>上測試（GPT-4、Claude 3.5 等）</li><li>優於現有 SOTA 記憶基準</li><li>NeurIPS 2025 接收（高品質驗證）</li></ul><hr><h2 id="對-harness-engineering-的影響" tabindex="-1">對 Harness Engineering 的影響 <a class="header-anchor" href="#對-harness-engineering-的影響" aria-label="Permalink to &quot;對 Harness Engineering 的影響&quot;">​</a></h2><h3 id="洞見-1-記憶不應是「點」而應是「圖」" tabindex="-1">洞見 #1：記憶不應是「點」而應是「圖」 <a class="header-anchor" href="#洞見-1-記憶不應是「點」而應是「圖」" aria-label="Permalink to &quot;洞見 #1：記憶不應是「點」而應是「圖」&quot;">​</a></h3><p>孤立的記憶片段需要上下文才能發揮價值。A-Mem 的連結機制讓相關知識自動關聯，減少 agent 需要的搜索次數。</p><h3 id="洞見-2-記憶創建時的質量決定檢索質量" tabindex="-1">洞見 #2：記憶創建時的質量決定檢索質量 <a class="header-anchor" href="#洞見-2-記憶創建時的質量決定檢索質量" aria-label="Permalink to &quot;洞見 #2：記憶創建時的質量決定檢索質量&quot;">​</a></h3><p>在記憶存入時花時間生成完整的結構化描述，比存入後優化檢索更有效。</p><h3 id="洞見-3-llm-能夠判斷記憶的連結關係" tabindex="-1">洞見 #3：LLM 能夠判斷記憶的連結關係 <a class="header-anchor" href="#洞見-3-llm-能夠判斷記憶的連結關係" aria-label="Permalink to &quot;洞見 #3：LLM 能夠判斷記憶的連結關係&quot;">​</a></h3><p>不需要規則引擎，LLM 本身能判斷哪些記憶應該相互連結，大幅降低記憶系統的工程複雜度。</p><hr><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv: <a href="https://arxiv.org/abs/2502.12110" target="_blank" rel="noreferrer">https://arxiv.org/abs/2502.12110</a></li><li>GitHub: <a href="https://github.com/agiresearch/a-mem" target="_blank" rel="noreferrer">https://github.com/agiresearch/a-mem</a></li></ul>`,33)])])}const p=a(i,[["render",l]]);export{g as __pageData,p as default};
